'use client';

import React from 'react';
import { AgentNode, AgentStatus } from '@/lib/metrics';

interface AgentHierarchyProps {
  agents: AgentNode[];
  selectedAgent: string | null;
  onSelectAgent: (id: string) => void;
}

const statusColors: Record<AgentStatus, string> = {
  working: 'bg-teal-500 shadow-teal-500/50',
  idle: 'bg-blue-500 shadow-blue-500/50',
  error: 'bg-red-500 shadow-red-500/50',
  offline: 'bg-slate-400',
};

const statusLabels: Record<AgentStatus, string> = {
  working: 'working',
  idle: 'idle',
  error: 'error',
  offline: 'offline',
};

function AgentRow({
  agent,
  isSelected,
  onClick,
}: {
  agent: AgentNode;
  isSelected: boolean;
  onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
      className={`w-full text-left px-4 py-3 flex items-start space-x-3 transition-all hover:bg-slate-50 ${
        isSelected 
          ? 'bg-gradient-to-r from-teal-50 to-transparent border-l-3 border-teal-600 shadow-sm' 
          : 'border-l-3 border-transparent'
      }`}
    >
      <div className="flex-shrink-0 mt-1">
        <div className={`w-2.5 h-2.5 rounded-full ${statusColors[agent.status]} shadow-lg`} />
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-center justify-between">
          <span className="font-semibold text-slate-900 text-sm truncate">{agent.name}</span>
        </div>
        <div className="text-xs text-slate-600 truncate mt-1 leading-snug">{agent.currentTask || 'No active task'}</div>
        <div className="flex items-center space-x-1.5 mt-1.5">
          <span className="text-[10px] text-slate-500 uppercase tracking-wider font-semibold">{statusLabels[agent.status]}</span>
          {agent.status === 'working' && <span className="text-[10px] text-teal-600">●</span>}
        </div>
      </div>
    </button>
  );
}

function LevelSection({
  title,
  level,
  agents,
  selectedAgent,
  onSelectAgent,
}: {
  title: string;
  level: 1 | 2 | 3;
  agents: AgentNode[];
  selectedAgent: string | null;
  onSelectAgent: (id: string) => void;
}) {
  const levelAgents = agents.filter((a) => a.level === level);

  if (levelAgents.length === 0) return null;

  return (
    <div className="mb-4">
      <div className="px-4 py-3 heading-section border-b border-slate-200 bg-slate-50/50">
        {title}
      </div>
      <div className="py-2">
        {levelAgents.map((agent) => (
          <AgentRow
            key={agent.id}
            agent={agent}
            isSelected={selectedAgent === agent.id}
            onClick={() => onSelectAgent(agent.id)}
          />
        ))}
      </div>
    </div>
  );
}

export function AgentHierarchy({
  agents,
  selectedAgent,
  onSelectAgent,
}: AgentHierarchyProps) {
  return (
    <div className="h-full flex flex-col bg-gradient-to-b from-slate-50 to-white border-r-2 border-slate-300">
      <div className="px-4 py-4 border-b-2 border-slate-300 bg-white shadow-sm">
        <h2 className="heading-section">Agent Hierarchy</h2>
      </div>

      <div className="flex-1 overflow-y-auto scrollbar-dark py-3">
        {/* Vertical connecting line */}
        <div className="relative">
          <div className="absolute left-[19px] top-0 bottom-0 w-px bg-slate-200" />

          <LevelSection
            title="Level 1: Strategy"
            level={1}
            agents={agents}
            selectedAgent={selectedAgent}
            onSelectAgent={onSelectAgent}
          />

          <LevelSection
            title="Level 2: Management"
            level={2}
            agents={agents}
            selectedAgent={selectedAgent}
            onSelectAgent={onSelectAgent}
          />

          <LevelSection
            title="Level 3: Execution"
            level={3}
            agents={agents}
            selectedAgent={selectedAgent}
            onSelectAgent={onSelectAgent}
          />
        </div>

        {agents.length === 0 && (
          <div className="px-4 py-8 text-center">
            <div className="text-slate-600 text-sm">No agents registered</div>
            <div className="text-slate-500 text-xs mt-1">Check swarm configuration</div>
          </div>
        )}
      </div>

      {/* Summary footer */}
      <div className="px-4 py-3 border-t-2 border-slate-300 bg-white shadow-inner text-xs text-slate-600">
        <div className="flex justify-between items-center">
          <span className="uppercase tracking-wider font-semibold">Total Agents</span>
          <span className="font-mono text-base font-bold text-slate-900">{agents.length}</span>
        </div>
      </div>
    </div>
  );
}
