'use client';

import React, { useState, useRef, useEffect } from 'react';
import { Search, X, ArrowDown, Trash2 } from 'lucide-react';
import { useLogStream } from '@/hooks/useLogStream';

interface LogStreamProps {
  agentId: string | null;
}

type LogLevel = 'debug' | 'info' | 'warn' | 'error';

const levelColors: Record<LogLevel, string> = {
  debug: 'text-slate-500',
  info: 'text-teal-700',
  warn: 'text-amber-700',
  error: 'text-red-700',
};

const levelBgColors: Record<LogLevel, string> = {
  debug: 'bg-slate-100 text-slate-700 border border-slate-200',
  info: 'bg-teal-50 text-teal-700 border border-teal-200',
  warn: 'bg-amber-50 text-amber-700 border border-amber-200',
  error: 'bg-red-50 text-red-700 border border-red-200',
};

export function LogStream({ agentId }: LogStreamProps) {
  const { logs, isConnected, clearLogs, connectionStatus } = useLogStream(agentId);
  const [searchQuery, setSearchQuery] = useState('');
  const [enabledLevels, setEnabledLevels] = useState<Set<LogLevel>>(
    new Set(['debug', 'info', 'warn', 'error'])
  );
  const [autoScroll, setAutoScroll] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);
  const isUserScrollingRef = useRef(false);

  // Filter logs based on severity and search query
  const filteredLogs = logs.filter((log) => {
    const levelMatch = enabledLevels.has(log.level);
    const searchMatch =
      !searchQuery ||
      log.message.toLowerCase().includes(searchQuery.toLowerCase());
    return levelMatch && searchMatch;
  });

  // Handle scroll detection
  const handleScroll = () => {
    if (!scrollRef.current) return;

    const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
    const isAtBottom = scrollTop + clientHeight >= scrollHeight - 50;

    if (!isUserScrollingRef.current) {
      // If user is not manually scrolling, auto-scroll stays enabled
      return;
    }

    // User is scrolling - detect if near bottom
    if (isAtBottom) {
      setAutoScroll(true);
    } else {
      setAutoScroll(false);
    }
  };

  // Track user scroll intent
  useEffect(() => {
    const container = scrollRef.current;
    if (!container) return;

    const onScrollStart = () => {
      isUserScrollingRef.current = true;
    };

    container.addEventListener('scroll', onScrollStart, { passive: true });
    return () => container.removeEventListener('scroll', onScrollStart);
  }, []);

  // Auto-scroll to bottom when new logs arrive
  useEffect(() => {
    if (autoScroll && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [filteredLogs, autoScroll]);

  const toggleLevel = (level: LogLevel) => {
    const newLevels = new Set(enabledLevels);
    if (newLevels.has(level)) {
      newLevels.delete(level);
    } else {
      newLevels.add(level);
    }
    setEnabledLevels(newLevels);
  };

  const handleJumpToLatest = () => {
    setAutoScroll(true);
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  // Format timestamp to HH:MM:SS
  const formatTime = (timestamp: string) => {
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour12: false,
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return timestamp;
    }
  };

  // Connection status indicator
  const getStatusColor = () => {
    switch (connectionStatus) {
      case 'connected':
        return 'bg-teal-600';
      case 'connecting':
        return 'bg-amber-500 animate-pulse';
      case 'disconnected':
        return 'bg-red-600';
      default:
        return 'bg-slate-400';
    }
  };

  if (!agentId) {
    return (
      <div className="h-full flex items-center justify-center bg-white border-l border-slate-200">
        <div className="text-center">
          <div className="text-slate-600 text-sm">Select an agent to view logs</div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-gradient-to-b from-white to-slate-50 border-l-2 border-slate-300 relative">
      {/* Header with connection status */}
      <div className="px-4 py-4 border-b-2 border-slate-300 bg-white shadow-sm flex items-center justify-between">
        <div className="flex items-center space-x-2">
          <div className={`w-2 h-2 rounded-full ${getStatusColor()} shadow-lg`} />
          <h2 className="heading-section">Log Stream</h2>
        </div>
        <div className="flex items-center space-x-2">
          <span className="text-xs text-slate-500 font-mono">{logs.length} entries</span>
          <button
            onClick={clearLogs}
            className="p-1.5 hover:bg-white rounded text-slate-500 hover:text-slate-900 transition-colors"
            title="Clear logs"
          >
            <Trash2 className="w-3.5 h-3.5" />
          </button>
        </div>
      </div>

      {/* Toolbar */}
      <div className="px-4 py-3 border-b border-slate-200 space-y-2.5 bg-slate-50/50">
        {/* Severity filters */}
        <div className="flex space-x-1">
          {(['debug', 'info', 'warn', 'error'] as LogLevel[]).map((level) => (
            <button
              key={level}
              onClick={() => toggleLevel(level)}
              className={`px-2 py-1 rounded text-xs font-medium transition-colors ${
                enabledLevels.has(level)
                  ? levelBgColors[level]
                  : 'bg-slate-100 text-slate-500 hover:text-slate-700'
              }`}
            >
              {level.toUpperCase()}
            </button>
          ))}
        </div>

        {/* Search */}
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
          <input
            type="text"
            placeholder="Filter logs..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-8 pr-8 py-1.5 bg-slate-50 border border-slate-200 rounded text-xs text-slate-800 placeholder:text-slate-500 focus:outline-none focus:border-slate-300"
          />
          {searchQuery && (
            <button
              onClick={() => setSearchQuery('')}
              className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-900"
            >
              <X className="w-3.5 h-3.5" />
            </button>
          )}
        </div>
      </div>

      {/* Log entries */}
      <div
        ref={scrollRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto scrollbar-dark font-mono text-xs p-4 space-y-1 tabular-nums bg-white/50"
      >
        {filteredLogs.length === 0 ? (
          <div className="text-center py-8 text-slate-600">
            {logs.length === 0 ? 'Waiting for logs...' : 'No logs match filters'}
          </div>
        ) : (
          filteredLogs.map((log, idx) => (
            <div key={idx} className="flex items-start space-x-2.5 py-1.5 px-2 hover:bg-white/80 rounded transition-colors">
              <span className="text-slate-500/80 whitespace-nowrap">[{formatTime(log.timestamp)}]</span>
              <span className={`uppercase font-bold w-12 shrink-0 ${levelColors[log.level]}`}>
                {log.level}
              </span>
              <span className="text-slate-800 break-all">{log.message}</span>
            </div>
          ))
        )}
      </div>

      {/* Jump to latest button */}
      {!autoScroll && (
        <button
          onClick={handleJumpToLatest}
          className="absolute bottom-4 right-4 flex items-center space-x-1 px-3 py-1.5 bg-teal-600 hover:bg-teal-500 text-white rounded text-xs font-medium shadow-lg transition-colors"
        >
          <ArrowDown className="w-3.5 h-3.5" />
          <span>Jump to latest</span>
        </button>
      )}
    </div>
  );
}
