'use client';

import React, { useState } from 'react';
import { Copy, CheckCircle2, AlertCircle, Clock, Server, User } from 'lucide-react';
import { AgentNode, AgentStatus } from '@/lib/metrics';
import { JarvisState, Task, ActivityEntry } from '@/lib/jarvis';

interface AgentDetailProps {
  agentId: string | null;
  agents: AgentNode[];
  state: JarvisState | undefined;
}

const statusColors: Record<AgentStatus, string> = {
  working: 'text-teal-700',
  idle: 'text-blue-700',
  error: 'text-red-700',
  offline: 'text-slate-500',
};

const statusBgColors: Record<AgentStatus, string> = {
  working: 'bg-teal-50 text-teal-700 border-teal-200',
  idle: 'bg-blue-50 text-blue-700 border-blue-200',
  error: 'bg-red-50 text-red-700 border-red-200',
  offline: 'bg-slate-100 text-slate-600 border-slate-200',
};

const statusIcons: Record<AgentStatus, typeof CheckCircle2> = {
  working: CheckCircle2,
  idle: Clock,
  error: AlertCircle,
  offline: Server,
};

const statusLabels: Record<AgentStatus, string> = {
  working: 'working',
  idle: 'idle',
  error: 'error',
  offline: 'offline',
};

type Tab = 'overview' | 'tasks' | 'state';

function formatTimestamp(timestamp: number): string {
  return new Date(timestamp * 1000).toLocaleString();
}

function TaskCard({ taskId, task }: { taskId: string; task: Task }) {
  const [expanded, setExpanded] = useState(false);

  const statusColors = {
    pending: 'bg-amber-50 text-amber-700 border-amber-200',
    in_progress: 'bg-blue-50 text-blue-700 border-blue-200',
    completed: 'bg-teal-50 text-teal-700 border-teal-200',
    failed: 'bg-red-50 text-red-700 border-red-200',
  };

  return (
    <div className="border border-slate-200 rounded-lg overflow-hidden mb-3 bg-white">
      <button
        onClick={() => setExpanded(!expanded)}
        className="w-full px-4 py-3 bg-slate-50 flex items-center justify-between hover:bg-slate-100 transition-colors"
      >
        <div className="flex items-center space-x-3">
          <span className="font-mono text-xs text-slate-500">{taskId}</span>
          <span className={`px-2 py-0.5 rounded text-xs border ${statusColors[task.status]}`}>
            {task.status}
          </span>
        </div>
        <div className="text-xs text-slate-500">
          {expanded ? 'Collapse' : 'Expand'}
        </div>
      </button>

      {expanded && (
        <div className="px-4 py-3 bg-white">
          {task.skill_hint && (
            <div className="mb-3">
              <span className="text-xs text-slate-500 uppercase tracking-wider">Skill</span>
              <p className="text-sm text-slate-800 mt-0.5">{task.skill_hint}</p>
            </div>
          )}

          <div className="mb-3">
            <span className="text-xs text-slate-500 uppercase tracking-wider">Created</span>
            <p className="text-sm text-slate-800 mt-0.5 font-mono">
              {formatTimestamp(task.created_at)}
            </p>
          </div>

          <div>
            <span className="text-xs text-slate-500 uppercase tracking-wider mb-2 block">Activity Log</span>
            <div className="space-y-2">
              {task.activity_log.map((entry: ActivityEntry, idx: number) => (
                <div key={idx} className="flex items-start space-x-3 text-xs">
                  <span className="text-slate-500 font-mono whitespace-nowrap">
                    {new Date(entry.timestamp * 1000).toLocaleTimeString()}
                  </span>
                  <span className={`px-1.5 py-0.5 rounded border ${statusBgColors[entry.status as AgentStatus] || 'bg-slate-100 text-slate-600 border-slate-200'}`}>
                    {entry.status}
                  </span>
                  <span className="text-slate-800 flex-1">{entry.entry}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export function AgentDetail({ agentId, agents, state }: AgentDetailProps) {
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const [copied, setCopied] = useState(false);

  const agent = agents.find((a) => a.id === agentId);

  if (!agentId || !agent) {
    return (
      <div className="h-full flex items-center justify-center bg-white">
        <div className="text-center">
          <User className="w-12 h-12 text-slate-300 mx-auto mb-3" />
          <p className="text-slate-600 text-sm">Select an agent from the hierarchy</p>
          <p className="text-slate-500 text-xs mt-1">View agent details, tasks, and state</p>
        </div>
      </div>
    );
  }

  // Get agent's tasks from state
  const agentTasks = state
    ? Object.entries(state.tasks).filter(
        ([, task]) =>
          task.metadata?.agent_id === agent.id ||
          String(task.metadata?.container_name || '').includes(agent.id)
      )
    : [];

  // Copy state JSON to clipboard
  const handleCopy = () => {
    if (state) {
      navigator.clipboard.writeText(JSON.stringify(state, null, 2));
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="h-full flex flex-col bg-gradient-to-b from-white to-slate-50">
      {/* Tab bar */}
      <div className="flex border-b-2 border-slate-300 bg-white shadow-sm px-2">
        {[
          { id: 'overview', label: 'Overview' },
          { id: 'tasks', label: 'Tasks' },
          { id: 'state', label: 'State' },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as Tab)}
            className={`flex-1 py-4 text-sm font-semibold transition-all ${
              activeTab === tab.id
                ? 'text-teal-700 border-b-3 border-teal-600 bg-teal-50/30'
                : 'text-slate-600 hover:text-slate-900 hover:bg-slate-50 border-b-3 border-transparent'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto scrollbar-dark p-6">
        {activeTab === 'overview' && (
          <div className="space-y-8">
            {/* Header */}
            <div className="flex items-start justify-between">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">{agent.name}</h2>
                <div className="flex items-center space-x-2 mt-2">
                  <span className="px-2.5 py-1 rounded text-xs font-bold bg-slate-900 text-white border border-slate-700">
                    LEVEL {agent.level}
                  </span>
                  {agent.reports_to && (
                    <span className="text-xs text-slate-600">
                      Reports to: <span className="text-slate-700">{agent.reports_to}</span>
                    </span>
                  )}
                </div>
              </div>
              <div className={`flex items-center px-4 py-2 rounded-lg text-sm font-bold border-2 shadow-sm ${statusBgColors[agent.status]}`}>
                {React.createElement(statusIcons[agent.status], { className: "w-4 h-4 mr-1.5" })}
                {statusLabels[agent.status].toUpperCase()}
              </div>
            </div>

            {/* Status details */}
            <div className="space-y-3">
              <div className="flex items-center justify-between py-2 border-b border-slate-200">
                <span className="text-sm text-slate-600">Container</span>
                <span className="font-mono text-sm text-slate-800">
                  {agent.container_name || '—'}
                </span>
              </div>

              {agent.currentTask && (
                <div className="py-2 border-b border-slate-200">
                  <span className="text-sm text-slate-600 block mb-1">Current Task</span>
                  <p className="text-sm text-slate-800">{agent.currentTask}</p>
                </div>
              )}

              {state && (
                <div className="flex items-center justify-between py-2 border-b border-slate-200">
                  <span className="text-sm text-slate-600">Last Updated</span>
                  <span className="font-mono text-sm text-slate-800">
                    {formatTimestamp(state.metadata.last_updated)}
                  </span>
                </div>
              )}
            </div>

            {/* Task summary */}
            <div className="bg-white rounded-lg p-6 border-2 border-slate-200 shadow-sm">
              <h3 className="heading-section mb-5">Task Summary</h3>
              <div className="grid grid-cols-3 gap-6">
                <div className="text-center p-3 bg-slate-50 rounded-lg border border-slate-200">
                  <div className="text-3xl font-bold text-slate-900">{agentTasks.length}</div>
                  <div className="text-xs text-slate-600 uppercase tracking-wider font-semibold mt-1">Total</div>
                </div>
                <div className="text-center p-3 bg-teal-50 rounded-lg border border-teal-200">
                  <div className="text-3xl font-bold text-teal-700">
                    {agentTasks.filter(([, t]) => t.status === 'completed').length}
                  </div>
                  <div className="text-xs text-teal-600 uppercase tracking-wider font-semibold mt-1">Completed</div>
                </div>
                <div className="text-center p-3 bg-red-50 rounded-lg border border-red-200">
                  <div className="text-3xl font-bold text-red-700">
                    {agentTasks.filter(([, t]) => t.status === 'failed').length}
                  </div>
                  <div className="text-xs text-red-600 uppercase tracking-wider font-semibold mt-1">Failed</div>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'tasks' && (
          <div>
            <h3 className="heading-section mb-5">
              Assigned Tasks ({agentTasks.length})
            </h3>

            {agentTasks.length === 0 ? (
              <div className="text-center py-8">
                <p className="text-slate-600 text-sm">No tasks assigned to this agent</p>
              </div>
            ) : (
              <div>
                {agentTasks.map(([taskId, task]) => (
                  <TaskCard key={taskId} taskId={taskId} task={task} />
                ))}
              </div>
            )}
          </div>
        )}

        {activeTab === 'state' && (
          <div>
            <div className="flex items-center justify-between mb-4">
              <div>
                <h3 className="heading-section">Raw State</h3>
                <p className="text-xs text-slate-500 mt-0.5">Raw Jarvis Protocol state for debugging</p>
              </div>
              <button
                onClick={handleCopy}
                className="flex items-center space-x-1 px-3 py-1.5 bg-slate-50 hover:bg-slate-100 rounded text-xs text-slate-700 transition-colors border border-slate-200"
              >
                {copied ? (
                  <>
                    <CheckCircle2 className="w-3.5 h-3.5 text-teal-700" />
                    <span>Copied</span>
                  </>
                ) : (
                  <>
                    <Copy className="w-3.5 h-3.5" />
                    <span>Copy JSON</span>
                  </>
                )}
              </button>
            </div>

            <pre className="bg-white border border-slate-200 rounded-lg p-4 overflow-auto text-xs font-mono text-slate-800 scrollbar-dark max-h-[60vh]">
              {state ? JSON.stringify(state, null, 2) : 'No state available'}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
}
