'use client';

import React from 'react';
import { Activity, Server, AlertCircle, CheckCircle2, Clock } from 'lucide-react';
import { SwarmMetrics } from '@/lib/metrics';
import { ProjectSelector } from '@/components/ProjectSelector';

interface GlobalMetricsProps {
  metrics: SwarmMetrics;
  projects?: Array<{ id: string; name: string; status: 'active' | 'idle' | 'error' }>;
  selectedProject?: string;
  onProjectSwitch?: (id: string) => void;
}

export function GlobalMetrics({ metrics, projects, selectedProject, onProjectSwitch }: GlobalMetricsProps) {
  return (
    <header className="h-20 bg-white border-b-2 border-slate-300 flex items-center justify-between px-6 shrink-0 tabular-nums shadow-sm">
      {/* Left: Branding + Project Selector */}
      <div className="flex items-center space-x-4">
        <div className="flex items-center space-x-2.5">
          <div className="p-1.5 bg-teal-600 rounded">
            <Activity className="w-4 h-4 text-white" />
          </div>
          <div className="flex items-center space-x-2">
            <span className="text-lg font-bold text-slate-900 tracking-tight">OPENCLAW</span>
            <span className="text-sm text-slate-500 font-medium tracking-wide">COMMAND</span>
          </div>
        </div>

        {/* Project Selector — shown when project list is available */}
        {projects && selectedProject && onProjectSwitch && (
          <ProjectSelector
            projects={projects}
            selectedId={selectedProject}
            onSelect={onProjectSwitch}
          />
        )}

        <div className="flex items-center text-xs text-teal-700 font-mono ml-2 px-2.5 py-1 bg-teal-50 rounded border border-teal-200">
          <span className="w-1.5 h-1.5 rounded-full bg-teal-600 animate-pulse mr-2" />
          LIVE
        </div>
      </div>

      {/* Center: Tier counts */}
      <div className="hidden md:flex items-center space-x-6">
        <div className="flex flex-col items-center px-4 py-1.5 bg-blue-50 rounded border border-blue-200">
          <span className="label-metric text-blue-600">STRATEGY</span>
          <span className="font-mono text-xl font-bold text-blue-700 mt-0.5">{metrics.totalByTier.L1}</span>
        </div>
        <div className="flex flex-col items-center px-4 py-1.5 bg-amber-50 rounded border border-amber-200">
          <span className="label-metric text-amber-600">MANAGEMENT</span>
          <span className="font-mono text-xl font-bold text-amber-700 mt-0.5">{metrics.totalByTier.L2}</span>
        </div>
        <div className="flex flex-col items-center px-4 py-1.5 bg-teal-50 rounded border border-teal-200">
          <span className="label-metric text-teal-600">EXECUTION</span>
          <span className="font-mono text-xl font-bold text-teal-700 mt-0.5">{metrics.totalByTier.L3}</span>
        </div>
      </div>

      {/* Right: Status counts */}
      <div className="flex items-center space-x-4 text-xs">
        <div className="flex items-center space-x-2 px-3 py-1.5 bg-teal-50 rounded border border-teal-200">
          <CheckCircle2 className="w-4 h-4 text-teal-600" />
          <div className="flex flex-col">
            <span className="text-[10px] text-teal-600 uppercase tracking-wider font-semibold">Active</span>
            <span className="font-mono text-sm text-teal-700 font-bold leading-none">{metrics.active}</span>
          </div>
        </div>
        <div className="flex items-center space-x-2 px-3 py-1.5 bg-slate-50 rounded border border-slate-200">
          <Clock className="w-4 h-4 text-slate-500" />
          <div className="flex flex-col">
            <span className="text-[10px] text-slate-600 uppercase tracking-wider font-semibold">Idle</span>
            <span className="font-mono text-sm text-slate-700 font-bold leading-none">{metrics.idle}</span>
          </div>
        </div>
        <div className="flex items-center space-x-2 px-3 py-1.5 bg-red-50 rounded border border-red-200">
          <AlertCircle className="w-4 h-4 text-red-600" />
          <div className="flex flex-col">
            <span className="text-[10px] text-red-600 uppercase tracking-wider font-semibold">Error</span>
            <span className="font-mono text-sm text-red-700 font-bold leading-none">{metrics.errored}</span>
          </div>
        </div>
      </div>

      {/* Mobile: Compact view */}
      <div className="md:hidden flex items-center space-x-3 text-xs">
        <div className="flex items-center space-x-1">
          <Server className="w-3.5 h-3.5 text-blue-600" />
          <span className="font-mono text-slate-700">
            {metrics.totalByTier.L1 + metrics.totalByTier.L2 + metrics.totalByTier.L3}
          </span>
        </div>
        <div className="flex items-center space-x-1">
          <CheckCircle2 className="w-3.5 h-3.5 text-teal-600" />
          <span className="font-mono text-teal-700">{metrics.active}</span>
        </div>
      </div>
    </header>
  );
}
