'use client';

import { useEffect, useRef } from 'react';
import { toast, ToastContainer } from 'react-toastify';
import { AgentNode, AgentStatus } from '@/lib/metrics';
import { JarvisState } from '@/lib/jarvis';

interface UseAgentStateMonitorProps {
  agents: AgentNode[];
  state: JarvisState | undefined;
}

/**
 * Custom hook that monitors agent state changes and fires toast notifications.
 *
 * Detects:
 * - Agent status changes (idle -> working, working -> error, etc.)
 * - New agents appearing (spawn)
 * - Agents disappearing (despawn)
 * - Recovery events
 */
export function useAgentStateMonitor({ agents, state }: UseAgentStateMonitorProps) {
  const previousAgentsRef = useRef<Map<string, AgentNode>>(new Map());
  const hasInitializedRef = useRef(false);

  useEffect(() => {
    if (!state) return;

    const currentAgents = new Map(agents.map((a) => [a.id, a]));
    const previousAgents = previousAgentsRef.current;

    // Skip on first render (initialization)
    if (!hasInitializedRef.current) {
      previousAgentsRef.current = currentAgents;
      hasInitializedRef.current = true;
      return;
    }

    // Detect despawned agents
    for (const [id, prevAgent] of previousAgents) {
      if (!currentAgents.has(id)) {
        toast.warn(
          <div>
            <span className="font-medium">{prevAgent.name}</span>
            <span className="text-slate-400"> stopped</span>
          </div>,
          {
            autoClose: 5000,
          }
        );
      }
    }

    // Detect spawned agents and status changes
    for (const [id, agent] of currentAgents) {
      const prevAgent = previousAgents.get(id);

      if (!prevAgent) {
        // New agent spawned
        toast.info(
          <div>
            <span className="font-medium">{agent.name}</span>
            <span className="text-slate-400"> spawned (L{agent.level})</span>
          </div>,
          {
            autoClose: 5000,
          }
        );
        continue;
      }

      // Status change detection
      if (prevAgent.status !== agent.status) {
        // Working -> Error
        if (agent.status === 'error') {
          const lastActivity = agent.currentTask || 'Unknown error';
          toast.error(
            <div>
              <div className="font-medium">{agent.name} failed</div>
              <div className="text-xs text-slate-400 truncate max-w-[300px]">{lastActivity}</div>
            </div>,
            {
              autoClose: 8000,
            }
          );
        }
        // Error -> Working/Idle (recovery)
        else if (prevAgent.status === 'error' && (agent.status === 'working' || agent.status === 'idle')) {
          toast.success(
            <div>
              <span className="font-medium">{agent.name}</span>
              <span className="text-emerald-400"> recovered</span>
            </div>,
            {
              autoClose: 3000,
            }
          );
        }
      }
    }

    // Update ref for next comparison
    previousAgentsRef.current = currentAgents;
  }, [agents, state]);
}

interface StatusToastProps {
  agents: AgentNode[];
  state: JarvisState | undefined;
}

/**
 * Component that mounts the ToastContainer and monitors agent state.
 */
export function StatusToast({ agents, state }: StatusToastProps) {
  useAgentStateMonitor({ agents, state });

  return (
    <ToastContainer
      position="top-right"
      theme="dark"
      pauseOnHover
      closeOnClick
      newestOnTop
      toastClassName="bg-white border border-slate-200 text-slate-900"
    />
  );
}
