'use client';

import React from 'react';
import { ChevronDown } from 'lucide-react';

interface ProjectSelectorProps {
  projects: Array<{ id: string; name: string; status: 'active' | 'idle' | 'error' }>;
  selectedId: string;
  onSelect: (id: string) => void;
  isLoading?: boolean;
}

const statusBadgeClasses: Record<'active' | 'idle' | 'error', string> = {
  active: 'bg-teal-100 text-teal-700',
  idle: 'bg-slate-100 text-slate-600',
  error: 'bg-red-100 text-red-700',
};

export function ProjectSelector({
  projects,
  selectedId,
  onSelect,
  isLoading = false,
}: ProjectSelectorProps) {
  const selectedProject = projects.find((p) => p.id === selectedId);

  if (isLoading) {
    return (
      <div className="flex items-center space-x-2">
        <div className="animate-pulse w-16 h-5 bg-slate-200 rounded" />
        <div className="animate-pulse w-28 h-8 bg-slate-200 rounded" />
      </div>
    );
  }

  return (
    <div className="flex items-center space-x-2">
      {/* Status badge for currently selected project */}
      {selectedProject && (
        <span
          className={`text-xs font-semibold px-2 py-0.5 rounded uppercase tracking-wide ${statusBadgeClasses[selectedProject.status]}`}
        >
          {selectedProject.status}
        </span>
      )}

      {/* Native select with ChevronDown overlay */}
      <div className="relative flex items-center">
        <select
          value={selectedId}
          onChange={(e) => onSelect(e.target.value)}
          className="appearance-none text-sm font-medium text-slate-800 bg-white border border-slate-300 rounded px-3 py-1.5 pr-7 focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-teal-500 cursor-pointer"
        >
          {projects.map((project) => (
            <option key={project.id} value={project.id}>
              {project.name}
            </option>
          ))}
        </select>
        <ChevronDown className="absolute right-2 w-3.5 h-3.5 text-slate-500 pointer-events-none" />
      </div>
    </div>
  );
}
