'use client';

import { useState, useEffect, useRef, useCallback } from 'react';

interface LogEntry {
  timestamp: string;
  level: 'debug' | 'info' | 'warn' | 'error';
  message: string;
}

type ConnectionStatus = 'connected' | 'connecting' | 'disconnected';

interface UseLogStreamReturn {
  logs: LogEntry[];
  isConnected: boolean;
  clearLogs: () => void;
  connectionStatus: ConnectionStatus;
}

const MAX_LOG_ENTRIES = 1000; // Circular buffer size

/**
 * Client-side hook for consuming container log SSE streams.
 *
 * Features:
 * - Circular buffer capped at 1000 entries
 * - Automatic reconnection with exponential backoff
 * - Connection status tracking
 * - Cleanup on unmount or agent change
 *
 * @param agentId - The agent ID to stream logs for, or null to pause
 * @returns Log stream state and controls
 */
export function useLogStream(agentId: string | null): UseLogStreamReturn {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');

  const eventSourceRef = useRef<EventSource | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const reconnectDelayRef = useRef(1000); // Start with 1 second
  const isMountedRef = useRef(true);
  const agentIdRef = useRef(agentId);

  // Update ref when agentId changes
  useEffect(() => {
    agentIdRef.current = agentId;
  }, [agentId]);

  const clearLogs = useCallback(() => {
    setLogs([]);
  }, []);

  const connect = useCallback(() => {
    // Don't connect if no agentId or component unmounted
    if (!agentId || !isMountedRef.current) return;

    // Close existing connection
    if (eventSourceRef.current) {
      eventSourceRef.current.close();
      eventSourceRef.current = null;
    }

    setConnectionStatus('connecting');

    try {
      const eventSource = new EventSource(`/api/logs/${encodeURIComponent(agentId)}`);
      eventSourceRef.current = eventSource;

      eventSource.onopen = () => {
        if (!isMountedRef.current) return;
        setConnectionStatus('connected');
        // Reset reconnect delay on successful connection
        reconnectDelayRef.current = 1000;
      };

      eventSource.onmessage = (event) => {
        if (!isMountedRef.current) return;

        try {
          const data = JSON.parse(event.data);

          // Handle connection confirmation
          if (data.connected) {
            console.log('[LogStream] Connected to container:', data.container);
            return;
          }

          // Handle log entry
          if (data.timestamp && data.message) {
            const entry: LogEntry = {
              timestamp: data.timestamp,
              level: data.level || 'info',
              message: data.message,
            };

            setLogs((prevLogs) => {
              const newLogs = [...prevLogs, entry];
              // Maintain circular buffer - cap at MAX_LOG_ENTRIES
              if (newLogs.length > MAX_LOG_ENTRIES) {
                return newLogs.slice(newLogs.length - MAX_LOG_ENTRIES);
              }
              return newLogs;
            });
          }
        } catch (error) {
          console.error('[LogStream] Error parsing log entry:', error);
        }
      };

      eventSource.addEventListener('container-stopped', () => {
        if (!isMountedRef.current) return;

        // Add system message for container stop
        const stopEntry: LogEntry = {
          timestamp: new Date().toISOString(),
          level: 'warn',
          message: 'Container stopped',
        };

        setLogs((prevLogs) => {
          const newLogs = [...prevLogs, stopEntry];
          if (newLogs.length > MAX_LOG_ENTRIES) {
            return newLogs.slice(newLogs.length - MAX_LOG_ENTRIES);
          }
          return newLogs;
        });

        setConnectionStatus('disconnected');
      });

      eventSource.onerror = () => {
        if (!isMountedRef.current) return;

        // Close current connection
        eventSource.close();
        eventSourceRef.current = null;

        setConnectionStatus('disconnected');

        // Exponential backoff reconnection
        reconnectDelayRef.current = Math.min(reconnectDelayRef.current * 2, 30000);

        // Schedule reconnection
        reconnectTimeoutRef.current = setTimeout(() => {
          if (isMountedRef.current && agentIdRef.current === agentId) {
            connect();
          }
        }, reconnectDelayRef.current);
      };
    } catch (error) {
      console.error('[LogStream] Error creating EventSource:', error);
      setConnectionStatus('disconnected');
    }
  }, [agentId]);

  // Connect when agentId changes
  useEffect(() => {
    isMountedRef.current = true;

    if (agentId) {
      connect();
    } else {
      // No agent selected - close connection and clear logs
      if (eventSourceRef.current) {
        eventSourceRef.current.close();
        eventSourceRef.current = null;
      }
      setConnectionStatus('disconnected');
    }

    // Cleanup on unmount or agentId change
    return () => {
      isMountedRef.current = false;

      if (eventSourceRef.current) {
        eventSourceRef.current.close();
        eventSourceRef.current = null;
      }

      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
        reconnectTimeoutRef.current = null;
      }
    };
  }, [agentId, connect]);

  const isConnected = connectionStatus === 'connected';

  return {
    logs,
    isConnected,
    clearLogs,
    connectionStatus,
  };
}
