"use client";

import React, { useState, useEffect, useCallback } from 'react';
import { useSwarmState } from '@/hooks/useSwarmState';
import { GlobalMetrics } from '@/components/GlobalMetrics';
import { AgentHierarchy } from '@/components/AgentHierarchy';
import { AgentDetail } from '@/components/AgentDetail';
import { LogStream } from '@/components/LogStream';
import { StatusToast } from '@/components/StatusToast';
import { Activity } from 'lucide-react';

// Matching interface for /api/projects response items
// (lib/projects.ts uses Node.js fs/path — not safe to import in client code)
interface ProjectInfo {
  id: string;
  name: string;
  status: 'active' | 'idle' | 'error';
}

const LS_KEY = 'openclaw:selected-project';

// --- LOADING STATE SKELETON ---
function LoadingState() {
  return (
    <div className="flex flex-col h-screen bg-gradient-to-br from-slate-50 to-slate-100">
      {/* Shimmer header */}
      <div className="h-16 bg-white border-b border-slate-200 flex items-center px-4">
        <div className="animate-shimmer w-48 h-6 rounded" />
        <div className="flex-1" />
        <div className="animate-shimmer w-32 h-4 rounded" />
      </div>

      {/* Shimmer panels */}
      <div className="flex-1 grid grid-cols-1 lg:grid-cols-12 gap-0 overflow-hidden">
        {/* Left panel skeleton */}
        <aside className="lg:col-span-3 bg-white border-r border-slate-200 p-4">
          <div className="animate-shimmer w-32 h-4 rounded mb-4" />
          {[...Array(6)].map((_, i) => (
            <div key={i} className="flex items-center space-x-3 mb-3">
              <div className="animate-shimmer w-2 h-2 rounded-full" />
              <div className="animate-shimmer w-full h-8 rounded" />
            </div>
          ))}
        </aside>

        {/* Center panel skeleton */}
        <main className="lg:col-span-5 bg-white p-4">
          <div className="animate-shimmer w-40 h-6 rounded mb-6" />
          <div className="space-y-4">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="animate-shimmer w-full h-16 rounded" />
            ))}
          </div>
        </main>

        {/* Right panel skeleton */}
        <aside className="lg:col-span-4 bg-white border-l border-slate-200 p-4">
          <div className="animate-shimmer w-24 h-4 rounded mb-4" />
          <div className="space-y-2">
            {[...Array(10)].map((_, i) => (
              <div key={i} className="animate-shimmer w-full h-4 rounded" />
            ))}
          </div>
        </aside>
      </div>
    </div>
  );
}

// --- ERROR STATE ---
function ErrorState({ error, onRetry }: { error: Error; onRetry: () => void }) {
  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center">
      <div className="text-center max-w-md px-4">
        <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4">
          <Activity className="w-8 h-8 text-red-600" />
        </div>
        <h1 className="text-xl font-bold text-slate-900 mb-2">Connection Failed</h1>
        <p className="text-slate-600 text-sm mb-6">
          Unable to connect to swarm state API. Check that the OpenClaw Gateway is running.
        </p>
        {error.message && (
          <p className="text-slate-500 text-xs font-mono mb-6 bg-white p-3 rounded border border-slate-200">
            {error.message}
          </p>
        )}
        <button
          onClick={onRetry}
          className="px-4 py-2 bg-teal-600 hover:bg-teal-500 text-white rounded text-sm font-medium transition-colors"
        >
          Retry Connection
        </button>
      </div>
    </div>
  );
}

// --- MAIN APP COMPONENT ---
export default function MissionControl() {
  const [selectedAgent, setSelectedAgent] = useState<string | null>(null);

  // Project selection state
  const [projects, setProjects] = useState<ProjectInfo[]>([]);
  const [selectedProject, setSelectedProject] = useState<string>('');
  const [isSwitching, setIsSwitching] = useState(false);

  // Fetch project list on mount and restore last selection from localStorage
  useEffect(() => {
    async function loadProjects() {
      try {
        const res = await fetch('/api/projects');
        if (!res.ok) return;
        const body = await res.json() as { projects: ProjectInfo[] };
        const list = body.projects ?? [];
        setProjects(list);

        if (list.length === 0) return;

        // Restore last-used project from localStorage
        let targetId: string;
        try {
          const stored = localStorage.getItem(LS_KEY);
          targetId = (stored && list.some((p) => p.id === stored))
            ? stored
            : list[0].id;
        } catch {
          // localStorage may be unavailable (SSR/private browsing)
          targetId = list[0].id;
        }

        setSelectedProject(targetId);
      } catch {
        // Project list fetch failed — selectedProject stays empty, hook uses fallback
      }
    }

    loadProjects();
  }, []);

  // Handle project switch: trigger skeleton, update state, persist to localStorage
  const handleProjectSwitch = useCallback((projectId: string) => {
    setIsSwitching(true);
    setSelectedProject(projectId);
    try {
      localStorage.setItem(LS_KEY, projectId);
    } catch {
      // localStorage write failure is non-fatal
    }
  }, []);

  const { agents, metrics, state, error, isLoading, isValidating } = useSwarmState(selectedProject);

  // Clear the switching skeleton when fresh data arrives
  useEffect(() => {
    if (isSwitching && !isValidating) {
      setIsSwitching(false);
    }
  }, [isValidating, isSwitching]);

  // Don't render until we know which project to show
  if (!selectedProject) {
    return <LoadingState />;
  }

  if (isLoading || isSwitching) {
    return <LoadingState />;
  }

  if (error) {
    return <ErrorState error={error} onRetry={() => window.location.reload()} />;
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50 overflow-hidden">
      {/* Status Toast Notifications */}
      <StatusToast agents={agents} state={state} />

      {/* Top: Global Metrics Bar */}
      <GlobalMetrics
        metrics={metrics}
        projects={projects}
        selectedProject={selectedProject}
        onProjectSwitch={handleProjectSwitch}
      />

      {/* Main: 3-Panel Layout */}
      <div className="flex-1 grid grid-cols-1 lg:grid-cols-12 gap-0 overflow-hidden">
        {/* Left: Agent Hierarchy (3 cols) */}
        <aside className="lg:col-span-3 h-full overflow-hidden">
          <AgentHierarchy
            agents={agents}
            selectedAgent={selectedAgent}
            onSelectAgent={setSelectedAgent}
          />
        </aside>

        {/* Center: Agent Detail (5 cols) */}
        <main className="lg:col-span-5 h-full overflow-hidden border-l border-slate-200">
          <AgentDetail
            agentId={selectedAgent}
            agents={agents}
            state={state}
          />
        </main>

        {/* Right: Log Stream (4 cols) */}
        <aside className="lg:col-span-4 h-full overflow-hidden">
          <LogStream agentId={selectedAgent} />
        </aside>
      </div>
    </div>
  );
}
