'use client';

import { useEffect, useRef, useCallback } from 'react';
import useSWR from 'swr';
import { AgentNode, SwarmMetrics } from '@/lib/metrics';
import { JarvisState } from '@/lib/jarvis';

interface SwarmStateResponse {
  agents: AgentNode[];
  metrics: SwarmMetrics;
  state: JarvisState;
  lastUpdated: string;
}

const fetcher = (url: string) => fetch(url).then((res) => res.json());

interface UseSwarmStateReturn {
  agents: AgentNode[];
  metrics: SwarmMetrics;
  state: JarvisState | undefined;
  error: Error | undefined;
  isLoading: boolean;
  isValidating: boolean;
}

/**
 * SWR + SSE hybrid hook for real-time swarm state
 *
 * Accepts a projectId to scope all data fetching to a specific project.
 * Changing projectId automatically invalidates the SWR cache (URL is the key)
 * and reconnects the SSE stream to the new project's stream endpoint.
 *
 * Uses SWR for polling with 2s refresh interval, and SSE for instant
 * invalidation when state changes are detected.
 */
export function useSwarmState(projectId: string): UseSwarmStateReturn {
  const swrUrl = projectId
    ? `/api/swarm?project=${encodeURIComponent(projectId)}`
    : '/api/swarm';

  const {
    data,
    error,
    mutate,
    isLoading,
    isValidating,
  } = useSWR<SwarmStateResponse>(swrUrl, fetcher, {
    refreshInterval: 2000,
    revalidateOnFocus: true,
    revalidateOnReconnect: true,
    dedupingInterval: 2000,
  });

  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const reconnectDelayRef = useRef(1000);
  const eventSourceRef = useRef<EventSource | null>(null);
  const isMountedRef = useRef(true);

  const connectSSE = useCallback(() => {
    if (!isMountedRef.current) return;

    // Close any existing connection before opening a new one
    if (eventSourceRef.current) {
      eventSourceRef.current.close();
      eventSourceRef.current = null;
    }

    try {
      const sseUrl = projectId
        ? `/api/swarm/stream?project=${encodeURIComponent(projectId)}`
        : '/api/swarm/stream';
      const eventSource = new EventSource(sseUrl);
      eventSourceRef.current = eventSource;

      eventSource.onmessage = (event) => {
        if (!isMountedRef.current) return;

        try {
          const parsed = JSON.parse(event.data) as SwarmStateResponse;
          if (parsed.agents) {
            // Full state payload received — inject directly into SWR cache
            // false = skip revalidation; SSE is the primary data source
            mutate(parsed, false);
            reconnectDelayRef.current = 1000; // reset backoff on successful data
          }
          // Error payloads (parsed.error) fall through without updating cache
        } catch {
          // Ignore parse errors for keepalive comments (": keepalive" is not JSON)
        }
      };

      eventSource.onerror = () => {
        if (!isMountedRef.current) return;

        // Close current connection
        eventSource.close();
        eventSourceRef.current = null;

        // Exponential backoff reconnection (1s, 2s, 4s ... max 30s)
        const delayMs = reconnectDelayRef.current;
        reconnectDelayRef.current = Math.min(reconnectDelayRef.current * 2, 30000);

        reconnectTimeoutRef.current = setTimeout(() => {
          if (isMountedRef.current) {
            connectSSE();
          }
        }, delayMs);
      };

      // Reset reconnect delay on successful connection
      reconnectDelayRef.current = 1000;
    } catch {
      // EventSource not supported, fall back to SWR polling only
    }
  }, [mutate, projectId]);

  useEffect(() => {
    isMountedRef.current = true;
    connectSSE();

    return () => {
      isMountedRef.current = false;

      if (eventSourceRef.current) {
        eventSourceRef.current.close();
        eventSourceRef.current = null;
      }

      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
        reconnectTimeoutRef.current = null;
      }
    };
  }, [connectSSE]);

  return {
    agents: data?.agents || [],
    metrics: data?.metrics || {
      totalByTier: { L1: 0, L2: 0, L3: 0 },
      active: 0,
      idle: 0,
      errored: 0,
      totalTasks: 0,
      completedTasks: 0,
      failedTasks: 0,
    },
    state: data?.state,
    error: error instanceof Error ? error : undefined,
    isLoading,
    isValidating,
  };
}
